import React from 'react';
import './skills.css';
import { motion } from 'framer-motion';
import SemiDonutChart from './SemiDonutChart';

const skillsData = {
  languages: [
    { txt: "HTML", percentage: 80 },
    { txt: "CSS", percentage: 70 },
    { txt: "JavaScript", percentage: 65 },
    { txt: "React JS", percentage: 75 },
    { txt: "C", percentage: 60 },
    { txt: "C++", percentage: 60 },
    { txt: "Python", percentage: 70 },
  ],
  libraries: [
    { txt: "NumPy", percentage: 60 },
    { txt: "Pandas", percentage: 55 },
    { txt: "Matplotlib", percentage: 50 },
    { txt: "Python", percentage: 70 },
  ]
};

const Skills = () => {
  return (
    <motion.div 
      className="skills-wrapper"
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.6 }}
      viewport={{ once: true }}
    >
      <h2 className="skills-title">💡 My Technical Skills</h2>

      <section className="skills-category">
        <h3 className="category-heading">Languages</h3>
        <div className="skills-cards">
          {skillsData.languages.map((skill, index) => (
            <motion.div 
              className="skill-card"
              key={index}
              whileHover={{ scale: 1.05 }}
            >
              <SemiDonutChart {...skill} fill="#00F5C9" />
              <p className="skill-name">{skill.txt}</p>
            </motion.div>
          ))}
        </div>
      </section>

      <section className="skills-category">
        <h3 className="category-heading">Libraries</h3>
        <div className="skills-cards">
          {skillsData.libraries.map((skill, index) => (
            <motion.div 
              className="skill-card"
              key={index}
              whileHover={{ scale: 1.05 }}
            >
              <SemiDonutChart {...skill} fill="#00F5C9" />
              <p className="skill-name">{skill.txt}</p>
            </motion.div>
          ))}
        </div>
      </section>
    </motion.div>
  );
};

export default Skills;
